1	-- Fix: publish_assignment_group_changes hits "canceling statement due to
2	-- statement timeout" when an instructor removes a student / moves members.
3	--
4	-- Two root causes:
5	--
6	--   1. The RPC never raised its statement_timeout, so it ran under the default
7	--      `authenticated` budget (~8s). Every other heavy RPC in this codebase sets
8	--      `statement_timeout to '3min'`; this one was missed. Worst-case calls
9	--      measured ~13s in production (pg_stat_statements), so they were cancelled.
10	--
11	--   2. The RPC mutates assignment_groups / assignment_groups_members row-at-a-time
12	--      in PL/pgSQL loops. Each single-row write fires the FOR EACH ROW trigger
13	--      `sync_repos_after_assignment_group_change`, which calls the assignment-wide
14	--      `create_all_repos_for_assignment_internal` (full scan of all students +
15	--      aggregate of all groups). So one publish ran that ~1s reconciliation 1+N
16	--      times (once per row touched) — the source of the 13s worst case.
17	--
18	-- Fix: raise the timeout to match the other RPCs, AND suppress the per-row
19	-- reconciliation for the duration of the batch via a transaction-local GUC, then
20	-- run the reconciliation exactly ONCE before the RPC returns. External callers
21	-- (ad-hoc membership writes outside this RPC) are unaffected — the trigger still
22	-- reconciles normally for them. 1+N full scans collapse to one (~13s -> ~1s).
23	
24	-- ── 1. Trigger fn: honor the batch-suppression flag ──────────────────────────
25	CREATE OR REPLACE FUNCTION public.sync_repos_after_assignment_group_change()
26	RETURNS trigger
27	LANGUAGE plpgsql
28	SECURITY DEFINER
29	SET search_path TO 'public'
30	AS $function$
31	DECLARE
32	  v_assignment_id bigint;
33	  v_class_id bigint;
34	  v_group_config public.assignment_group_mode;
35	  v_release timestamptz;
36	  v_template text;
37	BEGIN
38	  -- Batch callers (publish_assignment_group_changes) suppress the per-row
39	  -- reconciliation and run it once at the end instead. Skip entirely here.
40	  IF current_setting('pawtograder.suppress_repo_sync', true) = 'on' THEN
41	    IF TG_OP = 'DELETE' THEN
42	      RETURN OLD;
43	    END IF;
44	    RETURN NEW;
45	  END IF;
46	
47	  IF TG_TABLE_NAME = 'assignment_groups' THEN
48	    IF TG_OP = 'DELETE' THEN
49	      v_assignment_id := OLD.assignment_id;
50	      v_class_id := OLD.class_id;
51	    ELSE
52	      v_assignment_id := NEW.assignment_id;
53	      v_class_id := NEW.class_id;
54	    END IF;
55	  ELSIF TG_TABLE_NAME = 'assignment_groups_members' THEN
56	    IF TG_OP = 'DELETE' THEN
57	      v_assignment_id := OLD.assignment_id;
58	      v_class_id := OLD.class_id;
59	    ELSE
60	      v_assignment_id := NEW.assignment_id;
61	      v_class_id := NEW.class_id;
62	    END IF;
63	  ELSE
64	    RAISE WARNING 'sync_repos_after_assignment_group_change: unexpected table %', TG_TABLE_NAME;
65	    IF TG_OP = 'DELETE' THEN
66	      RETURN OLD;
67	    END IF;
68	    RETURN NEW;
69	  END IF;
70	
71	  SELECT a.group_config, a.release_date, a.template_repo
72	  INTO v_group_config, v_release, v_template
73	  FROM public.assignments a
74	  WHERE a.id = v_assignment_id AND a.class_id = v_class_id;
75	
76	  IF v_group_config IS NULL THEN
77	    IF TG_OP = 'DELETE' THEN
78	      RETURN OLD;
79	    END IF;
80	    RETURN NEW;
81	  END IF;
82	
83	  IF v_group_config NOT IN ('groups', 'both') THEN
84	    IF TG_OP = 'DELETE' THEN
85	      RETURN OLD;
86	    END IF;
87	    RETURN NEW;
88	  END IF;
89	
90	  IF v_template IS NULL OR v_template = '' THEN
91	    IF TG_OP = 'DELETE' THEN
92	      RETURN OLD;
93	    END IF;
94	    RETURN NEW;
95	  END IF;
96	
97	  IF v_release IS NULL OR v_release > now() THEN
98	    IF TG_OP = 'DELETE' THEN
99	      RETURN OLD;
100	    END IF;
101	    RETURN NEW;
102	  END IF;
103	
104	  RAISE NOTICE 'sync_repos_after_assignment_group_change: enqueue repos for assignment_id=%, class_id=% (source=% %)',
105	    v_assignment_id, v_class_id, TG_TABLE_NAME, TG_OP;
106	
107	  PERFORM public.create_all_repos_for_assignment_internal(v_class_id, v_assignment_id, false);
108	
109	  IF TG_OP = 'DELETE' THEN
110	    RETURN OLD;
111	  END IF;
112	  RETURN NEW;
113	END;
114	$function$;
115	
116	-- ── 2. RPC: raise timeout, suppress per-row trigger, reconcile once at the end ─
117	CREATE OR REPLACE FUNCTION public.publish_assignment_group_changes(
118	    p_class_id       bigint,
119	    p_assignment_id  bigint,
120	    -- groups_to_create: array of {name, member_ids}
121	    p_groups_to_create jsonb DEFAULT '[]'::jsonb,
122	    -- moves_to_fulfill: array of {profile_id, old_group_id, new_group_id}
123	    p_moves_to_fulfill jsonb DEFAULT '[]'::jsonb
124	)
125	RETURNS jsonb
126	LANGUAGE plpgsql
127	SECURITY DEFINER
128	SET search_path = public
129	AS $$
130	DECLARE
131	    v_caller_profile_id uuid;
132	    v_course_slug       text;
133	    v_github_org        text;
134	    v_template_repo     text;
135	    v_latest_sha        text;
136	    v_assignment_slug   text;
137	    v_group_config      text;
138	    v_release_date      timestamptz;
139	
140	    v_group             jsonb;
141	    v_move              jsonb;
142	    v_group_name        text;
143	    v_new_group_id      bigint;
144	    v_member_id         uuid;
145	    v_member_ids        jsonb;
146	
147	    v_old_gid           bigint;
148	    v_new_gid           bigint;
149	    v_profile_id        uuid;
150	    v_empty_gid         bigint;
151	
152	    v_membership_id     bigint;
153	    v_repo_record       record;
154	
155	    -- collect affected group IDs so we can do one permission sync per repo
156	    v_affected_groups   bigint[] := '{}';
157	    v_deleted_groups    bigint[] := '{}';
158	    -- empty groups we intentionally keep (they have submissions); excluded from
159	    -- the permission sync so their preserved repo's GitHub access is left as-is
160	    v_preserved_groups  bigint[] := '{}';
161	
162	    v_groups_created    integer := 0;
163	    v_members_added     integer := 0;
164	    v_members_moved     integer := 0;
165	    v_groups_dissolved  integer := 0;
166	    v_syncs_enqueued    integer := 0;
167	    v_errors            jsonb[] := '{}';
168	BEGIN
169	    -- Heavy batch operation: match the timeout other heavy RPCs use.
170	    -- Transaction-local so it resets when this RPC's transaction ends rather
171	    -- than leaking onto the pooled connection for subsequent requests.
172	    set local statement_timeout to '3min';
173	
174	    -- Suppress the per-row repo-sync trigger for the duration of this batch.
175	    -- The RPC mutates membership row-at-a-time, so leaving the trigger active
176	    -- would run the assignment-wide reconciliation once per row. We instead run
177	    -- it exactly once at the end (see Phase 4 below). Transaction-local: it
178	    -- resets automatically when this RPC's transaction ends.
179	    set local pawtograder.suppress_repo_sync = 'on';
180	
181	    -- ── auth ──────────────────────────────────────────────────────────────
182	    IF auth.uid() IS NULL THEN
183	        RAISE EXCEPTION 'Not authenticated';
184	    END IF;
185	    IF NOT public.authorizeforclassinstructor(p_class_id) THEN
186	        RAISE EXCEPTION 'Only instructors can publish group changes';
187	    END IF;
188	
189	    -- look up caller's profile for added_by
190	    SELECT private_profile_id INTO v_caller_profile_id
191	    FROM public.user_roles
192	    WHERE user_id = auth.uid()
193	      AND class_id = p_class_id
194	      AND role = 'instructor'
195	    LIMIT 1;
196	
197	    -- ── class + assignment metadata (one query) ──────────────────────────
198	    SELECT c.slug, c.github_org, a.slug, a.template_repo, a.latest_template_sha,
199	           a.group_config, a.release_date
200	    INTO   v_course_slug, v_github_org, v_assignment_slug, v_template_repo, v_latest_sha,
201	           v_group_config, v_release_date
202	    FROM   public.assignments a
203	    JOIN   public.classes c ON c.id = a.class_id
204	    WHERE  a.id = p_assignment_id AND a.class_id = p_class_id;
205	
206	    IF v_course_slug IS NULL THEN
207	        RAISE EXCEPTION 'Assignment % not found in class %', p_assignment_id, p_class_id;
208	    END IF;
209	
210	    -- ══════════════════════════════════════════════════════════════════════
211	    -- Phase 1: process moves on existing groups
212	    -- ══════════════════════════════════════════════════════════════════════
213	    FOR v_move IN SELECT * FROM jsonb_array_elements(p_moves_to_fulfill)
214	    LOOP
215	        v_profile_id := (v_move->>'profile_id')::uuid;
216	        v_old_gid    := (v_move->>'old_group_id')::bigint;   -- nullable
217	        v_new_gid    := (v_move->>'new_group_id')::bigint;   -- nullable
218	
219	        BEGIN
220	            -- validate group IDs belong to assignment before any mutations
221	            IF v_old_gid IS NOT NULL AND NOT EXISTS (
222	                SELECT 1 FROM public.assignment_groups
223	                WHERE id = v_old_gid
224	                  AND assignment_id = p_assignment_id
225	                  AND class_id = p_class_id
226	            ) THEN
227	                v_errors := array_append(v_errors, jsonb_build_object(
228	                    'profile_id', v_profile_id,
229	                    'error', format('Group %s does not belong to assignment %s', v_old_gid, p_assignment_id)
230	                ));
231	                CONTINUE;
232	            END IF;
233	            IF v_new_gid IS NOT NULL AND NOT EXISTS (
234	                SELECT 1 FROM public.assignment_groups
235	                WHERE id = v_new_gid
236	                  AND assignment_id = p_assignment_id
237	                  AND class_id = p_class_id
238	            ) THEN
239	                v_errors := array_append(v_errors, jsonb_build_object(
240	                    'profile_id', v_profile_id,
241	                    'error', format('Group %s does not belong to assignment %s', v_new_gid, p_assignment_id)
242	                ));
243	                CONTINUE;
244	            END IF;
245	
246	            -- remove from old group
247	            IF v_old_gid IS NOT NULL THEN
248	                SELECT id INTO v_membership_id
249	                FROM public.assignment_groups_members
250	                WHERE assignment_group_id = v_old_gid
251	                  AND profile_id = v_profile_id
252	                  AND class_id = p_class_id;
253	
254	                IF v_membership_id IS NULL THEN
255	                    v_errors := array_append(v_errors, jsonb_build_object(
256	                        'profile_id', v_profile_id,
257	                        'error', format('Student not in group %s', v_old_gid)
258	                    ));
259	                    CONTINUE;
260	                END IF;
261	
262	                DELETE FROM public.assignment_groups_members WHERE id = v_membership_id;
263	                v_affected_groups := array_append(v_affected_groups, v_old_gid);
264	            END IF;
265	
266	            -- add to new group
267	            IF v_new_gid IS NOT NULL THEN
268	                IF v_old_gid IS NULL THEN
269	                    -- moving from no-group into a group: deactivate individual submissions
270	                    UPDATE public.submissions
271	                    SET is_active = false
272	                    WHERE assignment_id = p_assignment_id
273	                      AND profile_id = v_profile_id;
274	                END IF;
275	
276	                INSERT INTO public.assignment_groups_members
277	                    (assignment_group_id, profile_id, assignment_id, class_id, added_by)
278	                VALUES
279	                    (v_new_gid, v_profile_id, p_assignment_id, p_class_id, v_caller_profile_id);
280	
281	                v_affected_groups := array_append(v_affected_groups, v_new_gid);
282	            END IF;
283	
284	            v_members_moved := v_members_moved + 1;
285	
286	        EXCEPTION WHEN OTHERS THEN
287	            v_errors := array_append(v_errors, jsonb_build_object(
288	                'profile_id', v_profile_id,
289	                'error', SQLERRM
290	            ));
291	        END;
292	    END LOOP;
293	
294	    -- ══════════════════════════════════════════════════════════════════════
295	    -- Phase 2: create new groups and add their initial members
296	    -- ══════════════════════════════════════════════════════════════════════
297	    FOR v_group IN SELECT * FROM jsonb_array_elements(p_groups_to_create)
298	    LOOP
299	        v_group_name := trim(v_group->>'name');
300	        v_member_ids := v_group->'member_ids';
301	
302	        BEGIN
303	            -- validate name
304	            IF v_group_name = '' OR v_group_name IS NULL THEN
305	                RAISE EXCEPTION 'Group name cannot be empty';
306	            END IF;
307	            IF length(v_group_name) > 36 THEN
308	                RAISE EXCEPTION 'Group name too long (max 36 chars)';
309	            END IF;
310	            IF v_group_name !~ '^[a-zA-Z0-9_-]+$' THEN
311	                RAISE EXCEPTION 'Group name must be alphanumeric, hyphens, or underscores';
312	            END IF;
313	
314	            -- uniqueness
315	            IF EXISTS (
316	                SELECT 1 FROM public.assignment_groups
317	                WHERE assignment_id = p_assignment_id AND lower(name) = lower(v_group_name)
318	            ) THEN
319	                RAISE EXCEPTION 'Group "%" already exists', v_group_name;
320	            END IF;
321	
322	            -- create the group
323	            INSERT INTO public.assignment_groups (name, assignment_id, class_id)
324	            VALUES (v_group_name, p_assignment_id, p_class_id)
325	            RETURNING id INTO v_new_group_id;
326	
327	            v_groups_created := v_groups_created + 1;
328	
329	            -- enqueue repo creation (with empty usernames; permission sync below)
330	            IF v_template_repo IS NOT NULL AND v_template_repo != '' AND v_github_org IS NOT NULL THEN
331	                PERFORM public.enqueue_github_create_repo(
332	                    p_class_id,
333	                    v_github_org,
334	                    v_course_slug || '-' || v_assignment_slug || '-group-' || v_group_name,
335	                    v_template_repo,
336	                    v_course_slug,
337	                    '{}'::text[],
338	                    false,
339	                    'batch-group-create-' || v_new_group_id::text,
340	                    p_assignment_id,
341	                    null::uuid,
342	                    v_new_group_id,
343	                    v_latest_sha
344	                );
345	            END IF;
346	
347	            -- add members
348	            IF v_member_ids IS NOT NULL AND jsonb_array_length(v_member_ids) > 0 THEN
349	                FOR v_member_id IN
350	                    SELECT (value#>>'{}')::uuid FROM jsonb_array_elements(v_member_ids) AS value
351	                LOOP
352	                    -- deactivate individual submissions when first entering a group
353	                    UPDATE public.submissions
354	                    SET is_active = false
355	                    WHERE assignment_id = p_assignment_id
356	                      AND profile_id = v_member_id;
357	
358	                    INSERT INTO public.assignment_groups_members
359	                        (assignment_group_id, profile_id, assignment_id, class_id, added_by)
360	                    VALUES
361	                        (v_new_group_id, v_member_id, p_assignment_id, p_class_id, v_caller_profile_id);
362	
363	                    v_members_added := v_members_added + 1;
364	                END LOOP;
365	            END IF;
366	
367	            v_affected_groups := array_append(v_affected_groups, v_new_group_id);
368	
369	        EXCEPTION WHEN OTHERS THEN
370	            v_errors := array_append(v_errors, jsonb_build_object(
371	                'group_name', v_group_name,
372	                'error', SQLERRM
373	            ));
374	        END;
375	    END LOOP;
376	
377	    -- ══════════════════════════════════════════════════════════════════════
378	    -- Phase 2b: dissolve empty groups (batch-final state after moves + creates)
379	    -- ══════════════════════════════════════════════════════════════════════
380	    FOR v_empty_gid IN
381	        SELECT ag.id
382	        FROM public.assignment_groups ag
383	        WHERE ag.assignment_id = p_assignment_id
384	          AND ag.class_id = p_class_id
385	          AND NOT EXISTS (
386	              SELECT 1 FROM public.assignment_groups_members agm
387	              WHERE agm.assignment_group_id = ag.id
388	          )
389	    LOOP
390	        -- Preserve groups that have submissions. Their repo holds graded/active
391	        -- work and is referenced by submissions (repository_id and
392	        -- repository_check_run_id), so deleting it would violate those FKs and
393	        -- destroy history. Keep the group, repo, check runs, and submissions
394	        -- intact; only fully dissolve groups whose repos have no submissions.
395	        IF EXISTS (
396	            SELECT 1 FROM public.submissions s
397	            WHERE s.assignment_group_id = v_empty_gid
398	        ) OR EXISTS (
399	            SELECT 1
400	            FROM public.submissions s
401	            JOIN public.repositories r ON r.id = s.repository_id
402	            WHERE r.assignment_group_id = v_empty_gid
403	        ) THEN
404	            v_preserved_groups := array_append(v_preserved_groups, v_empty_gid);
405	            CONTINUE;
406	        END IF;
407	
408	        DELETE FROM public.assignment_group_invitations
409	        WHERE assignment_group_id = v_empty_gid;
410	        DELETE FROM public.assignment_group_join_request
411	        WHERE assignment_group_id = v_empty_gid;
412	
413	        FOR v_repo_record IN
414	            SELECT r.id, r.repository
415	            FROM public.repositories r
416	            WHERE r.assignment_group_id = v_empty_gid
417	              AND r.repository IS NOT NULL
418	              AND position('/' in r.repository) > 0
419	        LOOP
420	            IF v_github_org IS NOT NULL THEN
421	                PERFORM public.enqueue_github_archive_repo(
422	                    p_class_id,
423	                    v_github_org,
424	                    split_part(v_repo_record.repository, '/', 2),
425	                    'batch-dissolve-' || v_empty_gid::text
426	                );
427	            END IF;
428	            DELETE FROM public.repository_check_runs WHERE repository_id = v_repo_record.id;
429	            DELETE FROM public.repositories WHERE id = v_repo_record.id;
430	        END LOOP;
431	
432	        DELETE FROM public.assignment_groups WHERE id = v_empty_gid;
433	        v_deleted_groups := array_append(v_deleted_groups, v_empty_gid);
434	        v_groups_dissolved := v_groups_dissolved + 1;
435	    END LOOP;
436	
437	    -- ══════════════════════════════════════════════════════════════════════
438	    -- Phase 3: enqueue ONE permission sync per affected repo
439	    -- ══════════════════════════════════════════════════════════════════════
440	    -- Deduplicate and exclude dissolved + preserved groups
441	    FOR v_repo_record IN
442	        SELECT DISTINCT r.id           AS repo_id,
443	               r.repository,
444	               r.assignment_group_id,
445	               r.is_github_ready
446	        FROM   unnest(v_affected_groups) AS gid(g)
447	        JOIN   public.repositories r ON r.assignment_group_id = gid.g
448	        WHERE  NOT (gid.g = ANY(v_deleted_groups))
449	          AND  NOT (gid.g = ANY(v_preserved_groups))
450	    LOOP
451	        BEGIN
452	            IF NOT v_repo_record.is_github_ready THEN
453	                CONTINUE;  -- will be synced when create_repo finishes
454	            END IF;
455	
456	            DECLARE
457	                v_usernames text[];
458	            BEGIN
459	                SELECT coalesce(array_remove(array_agg(u.github_username), NULL), '{}')
460	                INTO v_usernames
461	                FROM public.assignment_groups_members agm
462	                JOIN public.user_roles ur ON ur.private_profile_id = agm.profile_id
463	                JOIN public.users u ON u.user_id = ur.user_id
464	                WHERE agm.assignment_group_id = v_repo_record.assignment_group_id
465	                  AND ur.class_id = p_class_id
466	                  AND ur.role = 'student'
467	                  AND ur.github_org_confirmed = true
468	                  AND u.github_username IS NOT NULL
469	                  AND u.github_username != '';
470	
471	                IF v_repo_record.repository IS NOT NULL AND position('/' in v_repo_record.repository) > 0 THEN
472	                    PERFORM public.enqueue_github_sync_repo_permissions(
473	                        p_class_id,
474	                        v_github_org,
475	                        split_part(v_repo_record.repository, '/', 2),
476	                        v_course_slug,
477	                        coalesce(v_usernames, '{}'),
478	                        'batch-publish-' || p_assignment_id::text || '-g' || v_repo_record.assignment_group_id::text
479	                    );
480	                    v_syncs_enqueued := v_syncs_enqueued + 1;
481	                END IF;
482	            END;
483	        EXCEPTION WHEN OTHERS THEN
484	            v_errors := array_append(v_errors, jsonb_build_object(
485	                'repository_id', v_repo_record.repo_id,
486	                'error', SQLERRM
487	            ));
488	        END;
489	    END LOOP;
490	
491	    -- ══════════════════════════════════════════════════════════════════════
492	    -- Phase 4: reconcile repos ONCE for the whole batch
493	    -- ══════════════════════════════════════════════════════════════════════
494	    -- The per-row sync trigger was suppressed above; run its assignment-wide
495	    -- reconciliation a single time here. Mirror the trigger's guard conditions
496	    -- so we don't call the internal reconciler for assignments it would have
497	    -- skipped — notably it RAISES when the template repo is missing.
498	    IF v_group_config IN ('groups', 'both')
499	       AND v_template_repo IS NOT NULL AND v_template_repo != ''
500	       AND v_release_date IS NOT NULL AND v_release_date <= now()
501	    THEN
502	        BEGIN
503	            PERFORM public.create_all_repos_for_assignment_internal(p_class_id, p_assignment_id, false);
504	        EXCEPTION WHEN OTHERS THEN
505	            v_errors := array_append(v_errors, jsonb_build_object(
506	                'phase', 'reconcile',
507	                'error', SQLERRM
508	            ));
509	        END;
510	    END IF;
511	
512	    RETURN jsonb_build_object(
513	        'groups_created',   v_groups_created,
514	        'members_added',    v_members_added,
515	        'members_moved',    v_members_moved,
516	        'groups_dissolved', v_groups_dissolved,
517	        'syncs_enqueued',   v_syncs_enqueued,
518	        'errors',           to_jsonb(v_errors)
519	    );
520	END;
521	$$;
522	
523	REVOKE ALL ON FUNCTION public.publish_assignment_group_changes(bigint, bigint, jsonb, jsonb) FROM public;
524	GRANT EXECUTE ON FUNCTION public.publish_assignment_group_changes(bigint, bigint, jsonb, jsonb) TO authenticated;
525	
526	COMMENT ON FUNCTION public.publish_assignment_group_changes IS
527	'Atomically publish all staged group changes (new groups + member moves) for an
528	assignment in a single database call.  Validates inputs, creates groups, moves
529	members, dissolves empty groups, enqueues repo creation and ONE permission sync
530	per affected repo.  Suppresses the per-row sync_repos trigger for the duration of
531	the batch and runs repo reconciliation exactly once at the end (avoids 1+N
532	assignment-wide scans that caused statement timeouts).  Empty groups whose
533	repositories still have submissions are preserved (repo + check runs +
534	submissions kept intact) rather than deleted, to avoid FK violations and history loss.';
535

